/**
 * @summary Get comments for a post
 */
export const getGetPostCommentsUrl = (
  id: number,
  params?: GetPostCommentsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/posts/${id}/comments?${stringifiedParams}`
    : `/api/posts/${id}/comments`;
};

export const getPostComments = async (
  id: number,
  params?: GetPostCommentsParams,
  options?: RequestInit,
): Promise<CommentListResponse> => {
  return customFetch<CommentListResponse>(getGetPostCommentsUrl(id, params), {
    ...options,
    method: "GET",
  });
};

export const getGetPostCommentsQueryKey = (
  id: number,
  params?: GetPostCommentsParams,
) => {
  return [`/api/posts/${id}/comments`, ...(params ? [params] : [])] as const;
};

export const getGetPostCommentsQueryOptions = <
  TData = Awaited<ReturnType<typeof getPostComments>>,
  TError = ErrorType<unknown>,
>(
  id: number,
  params?: GetPostCommentsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getPostComments>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetPostCommentsQueryKey(id, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getPostComments>>> = ({
    signal,
  }) => getPostComments(id, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getPostComments>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetPostCommentsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getPostComments>>
>;
export type GetPostCommentsQueryError = ErrorType<unknown>;

/**
 * @summary Get comments for a post
 */

export function useGetPostComments<
  TData = Awaited<ReturnType<typeof getPostComments>>,
  TError = ErrorType<unknown>,
>(
  id: number,
  params?: GetPostCommentsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getPostComments>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetPostCommentsQueryOptions(id, params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

